        // If the input is negative, rotate the cube in the opposite direction
        if (horizontalInput < 0)
        {
            transform.Rotate(Vector3.right, rotation);
        }
        else if (horizontalInput > 0)
        {
            transform.Rotate(Vector3.left, rotation);
        }
    }
}
